# scripts/health_scorecard.py
# Run weekly from CI; outputs scorecard JSON for dashboard ingestion
import json
import subprocess
from datetime import date, timedelta
from pathlib import Path

def run(cmd): return subprocess.run(cmd, capture_output=True, text=True, check=True).stdout.strip()

def get_eval_pass_rate():
    # Read from the last 30 days of eval CI results
    results = json.loads(Path("evals/results/summary-30d.json").read_text())
    total = results["total_cases"]
    passed = results["passed_cases"]
    return round(passed / total * 100, 1) if total else 0.0

def get_active_waiver_count():
    waiver_dir = Path(".approved-dependencies/waivers")
    today = date.today()
    return sum(
        1 for f in waiver_dir.glob("*.json")
        if date.fromisoformat(json.loads(f.read_text())["expiry"]) >= today
    )

def get_deploy_frequency():
    # Count deployments in the last 7 days from git tags
    since = (date.today() - timedelta(days=7)).isoformat()
    tags = run(["git", "tag", "--list", "deploy/*", f"--sort=-version:refname",
                 f"--after={since}"])
    return len([t for t in tags.splitlines() if t])

scorecard = {
    "date": date.today().isoformat(),
    "quality": {
        "eval_pass_rate": get_eval_pass_rate(),
    },
    "security": {
        "active_waiver_count": get_active_waiver_count(),
    },
    "delivery": {
        "deploy_frequency_7d": get_deploy_frequency(),
    },
}

output = Path("scorecard-latest.json")
output.write_text(json.dumps(scorecard, indent=2))
print(f"Scorecard written to {output}")
